    "lyricsHtml": "\n<span class=\"lyric-line\">[Intro] </span>\n\n    <span class=\"chord\" data-chord=\"D\">D</span> \n\n\n    <span class=\"chord\" data-chord=\"F#m\">F#m</span>  \n\n\n    <span class=\"chord\" data-chord=\"A\">A</span>\n\n\n<span class=\"lyric-line\">[Primeira Parte] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>                 <span class=\"chord\" data-chord=\"Bm\">Bm</span>               <span class=\"chord\" data-chord=\"F#m\">F#m</span>\n<span class=\"lyric-line\">Words are flowing out like endless rain into a paper cup</span>\n     <span class=\"chord\" data-chord=\"Em7\">Em7</span>                          <span class=\"chord\" data-chord=\"A\">A</span>              <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">They slither wildly as they slip away across the universe</span>\n<span class=\"chord\" data-chord=\"D\">D</span>                <span class=\"chord\" data-chord=\"Bm\">Bm</span>               <span class=\"chord\" data-chord=\"F#m\">F#m</span>\n<span class=\"lyric-line\">Pools of sorrow, waves of joy are drifting through my opened mind</span>\n  <span class=\"chord\" data-chord=\"Em7\">Em7</span>            <span class=\"chord\" data-chord=\"Gm\">Gm</span>\n<span class=\"lyric-line\">Possessing and caressing me</span>\n \n<span class=\"lyric-line\">[Refrão] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>             <span class=\"chord\" data-chord=\"A7sus4\">A7sus4</span> <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Jai guru deva om</span>\n<span class=\"chord\" data-chord=\"A\">A</span>                         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"G\">G</span>                         <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"A\">A</span>                         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"G\">G</span>                         <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n \n<span class=\"lyric-line\">[Segunda Parte] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>         <span class=\"chord\" data-chord=\"Bm\">Bm</span>                 <span class=\"chord\" data-chord=\"F#m\">F#m</span>                            <span class=\"chord\" data-chord=\"Em7\">Em7</span>\n<span class=\"lyric-line\">Images of broken light which dance before me like a million eyes</span>\n                        <span class=\"chord\" data-chord=\"A\">A</span>            <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">They call me on and on across the universe</span>\n<span class=\"chord\" data-chord=\"D\">D</span>                <span class=\"chord\" data-chord=\"Bm\">Bm</span>              <span class=\"chord\" data-chord=\"F#m\">F#m</span>\n<span class=\"lyric-line\">Thoughts meander like a restless wind inside a letterbox</span>\n     <span class=\"chord\" data-chord=\"Em7\">Em7</span>                               <span class=\"chord\" data-chord=\"A\">A</span>              <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">They tumble blindly as they make their way across the universe</span>\n \n<span class=\"lyric-line\">[Refrão] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>             <span class=\"chord\" data-chord=\"A7sus4\">A7sus4</span>\n<span class=\"lyric-line\">Jai guru deva om</span>\n<span class=\"chord\" data-chord=\"A\">A</span>                         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"G\">G</span>                         <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"A\">A</span>                         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"G\">G</span>                         <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n \n<span class=\"lyric-line\">[Terceira Parte] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>                   <span class=\"chord\" data-chord=\"Bm\">Bm</span>                 <span class=\"chord\" data-chord=\"F#m\">F#m</span>\n<span class=\"lyric-line\">Sounds of laughter, shades of life are ringing through my opened ears</span>\n  <span class=\"chord\" data-chord=\"Em7\">Em7</span>          <span class=\"chord\" data-chord=\"Gm\">Gm</span>\n<span class=\"lyric-line\">Inciting and inviting me</span>\n<span class=\"chord\" data-chord=\"D\">D</span>            <span class=\"chord\" data-chord=\"Bm\">Bm</span>               <span class=\"chord\" data-chord=\"F#m\">F#m</span>                             <span class=\"chord\" data-chord=\"Em7\">Em7</span>\n<span class=\"lyric-line\">Limitless, undying love which shines around me like a million suns</span>\n                        <span class=\"chord\" data-chord=\"A\">A</span>            <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">And calls me on and on across the universe</span>\n \n<span class=\"lyric-line\">[Refrão] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>             <span class=\"chord\" data-chord=\"A7sus4\">A7sus4</span>\n<span class=\"lyric-line\">Jai guru deva om</span>\n<span class=\"chord\" data-chord=\"A\">A</span>                         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"G\">G</span>                         <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"A\">A</span>                         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n<span class=\"chord\" data-chord=\"G\">G</span>                         <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Nothing's gonna change my world</span>\n  \n<span class=\"lyric-line\">[Final] </span>\n\n<span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Jai guru deva</span>\n<span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Jai guru deva</span>\n",
